            $page::registerNavigationItems();
        }

        foreach ($this->panel->getPageConfigurations() as $configuration) {
            Filament::setCurrentPageConfigurationKey($configuration->getKey());

            $configuration->page::registerNavigationItems();

            Filament::setCurrentPageConfigurationKey(null);
        }

        foreach ($this->panel->getResources() as $resource) {
            $resource::registerNavigationItems();
        }

        foreach ($this->panel->getResourceConfigurations() as $configuration) {
            Filament::setCurrentResourceConfigurationKey($configuration->getKey());

            $configuration->resource::registerNavigationItems();

            Filament::setCurrentResourceConfigurationKey(null);
        }

        $this->isNavigationMounted = true;
    }

public function getRelationship(): Relation | Builder
    {
        $model = $this->getTable()->getModel();

        $record = app($model);

        $relationship = null;

        $relationshipName = $this->getRelationshipName();

        foreach (explode('.', $relationshipName) as $nestedRelationshipName) {
            if ($record->hasAttribute($nestedRelationshipName)) {
                $relationship = null;

                break;
            }

            if (! $record->isRelation($nestedRelationshipName)) {
                $relationship = null;

                break;
            }

            $relationship = $record->{$nestedRelationshipName}();
            $record = $relationship->getRelated();
        }

        if (! $relationship) {
            throw new LogicException("The relationship [{$relationshipName}] does not exist on the model [{$model}].");
        }

        return $relationship;
    }

public function test_push_mode_syncs_url_on_initial_load_when_value_restored_from_session()
    {
        $this->beforeServingApplication(function () {
            app('livewire')->component('session-url-push', SessionUrlPushComponent::class);

            Route::get('/session-url-push', function () {
                return app('livewire')->new('session-url-push')();
            })->middleware('web');
        });

        $this->browse(function ($browser) {
            $browser
                ->visit('/session-url-push')
                ->waitForLivewireToLoad()
                ->assertQueryStringMissing('search')
                ->assertInputValue('@search', '')

                // Type a value — it should update the query string and store in session...
                ->waitForLivewire()->type('@search', 'hello')
                ->assertQueryStringHas('search', 'hello')

                // Revisit the page with a clean URL — session should restore
                // the value AND the query string should reflect it...
                ->visit('/session-url-push')
                ->waitForLivewireToLoad()
                ->assertInputValue('@search', 'hello')
                ->assertQueryStringHas('search', 'hello')
            ;
        });
    }

public function relationship(string | Closure | null $name = null, ?Closure $modifyQueryUsing = null, ?Closure $modifyRecordsUsing = null): static
    {
        $this->relationship = $name ?? $this->getName();
        $this->modifyRelationshipQueryUsing = $modifyQueryUsing;
        $this->modifyRelationshipRecordsUsing = $modifyRecordsUsing;

        $this->afterStateHydrated(static function (Repeater $component): void {
            if (! is_array($component->hydratedDefaultState)) {
                return;
            }

            $component->mergeHydratedDefaultStateWithItemsState();
        });

        $this->loadStateFromRelationshipsUsing(static function (Repeater $component): void {
            $component->clearCachedExistingRecords();

            $component->fillFromRelationship();
        });

        $this->saveRelationshipsUsing(static function (Repeater $component): void {
            $component->saveToRelationship();
        });

        $this->dehydrated(false);

        $this->reorderable(false);

        return $this;
    }

public function getInValidationRuleValues(): ?array
    {
        $values = parent::getInValidationRuleValues();

        if ($values !== null) {
            return $values;
        }

        if (! $this->hasRelationship()) {
            return null;
        }

        $state = $this->getState();

        if (blank($state)) {
            return null;
        }

        $relationship = Relation::noConstraints(fn () => $this->getRelationship());
        $relationshipQuery = app(RelationshipJoiner::class)->prepareQueryForNoConstraints($relationship);

        $relatedKeyName = $relationship->getRelated()->getKeyName();
        $qualifiedRelatedKeyName = $relationshipQuery->qualifyColumn($relatedKeyName);

        if ($this->isMultiple()) {
            $stateArray = Arr::wrap($state);

            if (empty($stateArray)) {
                return null;
            }

            return $relationshipQuery
                ->whereIn($qualifiedRelatedKeyName, $stateArray)
                ->pluck($relatedKeyName)
                ->map(static fn ($id): string => (string) $id)
                ->all();
        }

        $exists = $relationshipQuery
            ->where($qualifiedRelatedKeyName, $state)
            ->exists();

        return $exists ? null : [];
    }

public function generateNavigationItems(array $components): array
    {
        $parameters = $this->getSubNavigationParameters();

        $items = [];

        foreach ($components as $component) {
            $isResourcePage = is_subclass_of($component, ResourcePage::class);

            $shouldRegisterNavigation = $isResourcePage ?
                $component::shouldRegisterNavigation($parameters) :
                $component::shouldRegisterNavigation();

            if (! $shouldRegisterNavigation) {
                continue;
            }

            $canAccess = $isResourcePage ?
                $component::canAccess($parameters) :
                $component::canAccess();

            if (! $canAccess) {
                continue;
            }

            $pageItems = $isResourcePage ?
                $component::getNavigationItems($parameters) :
                $component::getNavigationItems();

            $items = [
                ...$items,
                ...$pageItems,
            ];
        }

        return $items;
    }

public function mountHasFilters(): void
    {
        $shouldPersistFiltersInSession = $this->persistsFiltersInSession();
        $filtersSessionKey = $this->getFiltersSessionKey();

        if (! count($this->filters ?? [])) {
            $this->filters = null;
        }

        if (
            ($this->filters === null) &&
            $shouldPersistFiltersInSession &&
            session()->has($filtersSessionKey)
        ) {
            $this->filters = session()->get($filtersSessionKey);
        }

        // https://github.com/filamentphp/filament/pull/7999
        if ($this->filters) {
            $this->normalizeTableFilterValuesFromQueryString($this->filters);
        }

        if (method_exists($this, 'getFiltersForm')) {
            $this->getFiltersForm()->fill($this->filters);
        }

        if ($shouldPersistFiltersInSession) {
            session()->put(
                $filtersSessionKey,
                $this->filters,
            );
        }
    }

public function save(): void
    {
        try {
            $this->beginDatabaseTransaction();

            $this->callHook('beforeValidate');

            $data = $this->form->getState();

            $this->callHook('afterValidate');

            $data = $this->mutateFormDataBeforeSave($data);

            $this->callHook('beforeSave');

            $this->handleRecordUpdate($this->tenant, $data);

            $this->callHook('afterSave');
        } catch (Halt $exception) {
            $exception->shouldRollbackDatabaseTransaction() ?
                $this->rollBackDatabaseTransaction() :
                $this->commitDatabaseTransaction();

            return;
        } catch (Throwable $exception) {
            $this->rollBackDatabaseTransaction();

            throw $exception;
        }

        $this->commitDatabaseTransaction();

        $this->getSavedNotification()?->send();

        if ($redirectUrl = $this->getRedirectUrl()) {
            $this->redirect($redirectUrl, navigate: FilamentView::hasSpaMode($redirectUrl));
        }
    }

public function register(): void
    {
        abort_unless(static::canView(), 404);

        try {
            $this->beginDatabaseTransaction();

            $this->callHook('beforeValidate');

            $data = $this->form->getState();

            $this->callHook('afterValidate');

            $data = $this->mutateFormDataBeforeRegister($data);

            $this->callHook('beforeRegister');

            $this->tenant = $this->handleRegistration($data);

            $this->form->model($this->tenant)->saveRelationships();

            $this->callHook('afterRegister');
        } catch (Halt $exception) {
            $exception->shouldRollbackDatabaseTransaction() ?
                $this->rollBackDatabaseTransaction() :
                $this->commitDatabaseTransaction();

            return;
        } catch (Throwable $exception) {
            $this->rollBackDatabaseTransaction();

            throw $exception;
        }

        $this->commitDatabaseTransaction();

        if ($redirectUrl = $this->getRedirectUrl()) {
            $this->redirect($redirectUrl, navigate: FilamentView::hasSpaMode($redirectUrl));
        }
    }

public function boot(): void
    {
        if ($this->hasTenancy()) {
            foreach ($this->getResources() as $resource) {
                $resource::observeTenancyModelCreation($this);
                $resource::registerTenancyModelGlobalScope($this);
            }
        }

        $this->registerAssets();

        FilamentColor::register($this->getColors());

        FilamentIcon::register($this->getIcons());

        FilamentView::spa($this->hasSpaMode(), $this->hasSpaPrefetching());
        FilamentView::spaUrlExceptions($this->getSpaUrlExceptions());

        $this->registerRenderHooks();

        if ($this->hasDatabaseTransactions()) {
            Action::configureUsing(
                fn (Action $action) => $action->databaseTransaction(),
            );
        }

        foreach ($this->plugins as $plugin) {
            $plugin->boot($this);
        }

        foreach ($this->bootCallbacks as $callback) {
            $callback($this);
        }
    }

public static function getGlobalSearchResults(string $search): Collection
    {
        $query = static::getGlobalSearchEloquentQuery();

        static::applyGlobalSearchAttributeConstraints($query, $search);

        static::modifyGlobalSearchQuery($query, $search);

        return $query
            ->limit(static::getGlobalSearchResultsLimit())
            ->get()
            ->map(function (Model $record): ?GlobalSearchResult {
                $url = static::getGlobalSearchResultUrl($record);

                if (blank($url)) {
                    return null;
                }

                return new GlobalSearchResult(
                    title: static::getGlobalSearchResultTitle($record),
                    url: $url,
                    details: static::getGlobalSearchResultDetails($record),
                    actions: array_map(
                        fn (Action $action) => $action->hasRecord() ? $action : $action->record($record),
                        static::getGlobalSearchResultActions($record),
                    ),
                );
            })
            ->filter();
    }

public function getStateRelationship(Model $record, ?string $statePath = null): ?Relation
    {
        if ($this->stateRelationshipCache) {
            return $this->stateRelationshipCache;
        }

        if (blank($statePath) && (! str($this->getStateRelationshipPath())->contains('.'))) {
            return null;
        }

        $relationship = null;

        foreach (explode('.', $statePath ?? $this->getStateRelationshipName()) as $nestedRelationshipName) {
            if ($record->hasAttribute($nestedRelationshipName)) {
                $relationship = null;

                break;
            }

            if (! $record->isRelation($nestedRelationshipName)) {
                $relationship = null;

                break;
            }

            $relationship = $record->{$nestedRelationshipName}();
            $record = $relationship->getRelated();
        }

        return $this->stateRelationshipCache = $relationship;
    }

public function callAfterStateUpdated(bool $shouldBubbleToParents = true): static
    {
        $this->callAfterStateUpdatedHooks();

        if ($this->isPartiallyRenderedAfterStateUpdated()) {
            $this->partiallyRender();
        }

        if (filled($components = $this->getComponentsToPartiallyRenderAfterStateUpdated())) {
            foreach ($components as $key) {
                $component = $this->getLivewire()->getSchemaComponent($this->resolveRelativeKey($key), withHidden: true);

                if (! $component) {
                    throw new InvalidArgumentException("Could not find component [{$key}] to partially render.");
                }

                $component->partiallyRender();
            }
        }

        if ($this->isRenderlessAfterStateUpdated()) {
            $this->skipRender();
        }

        if ($shouldBubbleToParents) {
            $this->getContainer()->getParentComponent()?->callAfterStateUpdated();
        }

        return $this;
    }

public function callAfterStateUpdated(string $path): bool
    {
        try {
            foreach ($this->getComponents(withActions: false, withHidden: true) as $component) {
                $componentStatePath = $component->getStatePath();

                if ($componentStatePath === $path) {
                    $component->callAfterStateUpdated(shouldBubbleToParents: false);

                    return true;
                }

                if (str($path)->startsWith("{$componentStatePath}.")) {
                    $component->callAfterStateUpdated(shouldBubbleToParents: false);
                }

                foreach ($component->getChildSchemas() as $childSchema) {
                    if ($childSchema->callAfterStateUpdated($path)) {
                        return true;
                    }
                }
            }

            return false;
        } finally {
            if ($this->shouldPartiallyRender($path)) {
                app(PartialsComponentHook::class)->renderPartial($this->getLivewire(), fn (): array => [
                    "schema.{$this->getKey()}" => $this->toHtml(...),
                ]);
            }
        }
    }

